mapper.select:
SELECT
f.follow_id, u.name, f.created_at, f.active, u.user_id,
(SELECT
SUM(active)
FROM follow WHERE workshop_id = #{workshopId}
) AS totalFollow
FROM follow f
JOIN user u ON f.user_id = u.user_id
WHERE f.workshop_id = #{workshopId}
AND f.active = TRUE

mapper.update:
UPDATE follow
SET active = #{active}, updated_at = NOW()
WHERE follow_id = #{followId}
